# Structured assessment questionnaire — store responses as evidence
ANTHROPIC_ASSESSMENT_QUESTIONS = [
    {
        "domain": "Security",
        "question": "Does Anthropic hold a current SOC 2 Type II certification covering the API services used by this firm?",
        "evidence_required": "SOC 2 Type II report (issued within 12 months)",
        "pass_criterion": "Report issued within 12 months; no critical exceptions",
    },
    {
        "domain": "Data",
        "question": "Does Anthropic's DPA confirm that prompt data is not used to train models by default for API customers?",
        "evidence_required": "DPA clause reference or zero-data-retention policy confirmation",
        "pass_criterion": "DPA explicitly states prompt data not used for training without opt-in",
    },
    {
        "domain": "Data",
        "question": "What is the data retention period for prompt and completion data?",
        "evidence_required": "DPA data retention schedule",
        "pass_criterion": "Retention period does not exceed the firm's data classification requirement for the data type",
    },
    {
        "domain": "Resilience",
        "question": "What is Anthropic's published SLA for the API (availability and latency)?",
        "evidence_required": "Service Level Agreement or API status page history",
        "pass_criterion": "99.9% monthly availability OR compensating control (fallback provider) documented",
    },
    {
        "domain": "Subprocessors",
        "question": "Which subprocessors does Anthropic use for the API service (e.g., cloud infrastructure providers)?",
        "evidence_required": "Subprocessor list from DPA or Anthropic trust page",
        "pass_criterion": "All subprocessors identified; firm has no contractual prohibition on any listed subprocessor",
    },
    {
        "domain": "Incident Response",
        "question": "Does Anthropic commit to notifying the firm within 72 hours of a security incident affecting firm data?",
        "evidence_required": "DPA or MSA incident notification clause",
        "pass_criterion": "72-hour notification commitment present",
    },
    {
        "domain": "AI Safety",
        "question": "Has Anthropic published a model card or safety evaluation for the model version in use?",
        "evidence_required": "Link to Anthropic model card or safety report",
        "pass_criterion": "Document exists; known limitations are consistent with the firm's intended use",
    },
]
